  1→/**
  2→ * KeyboardShortcutService - Manages keyboard shortcuts for timeline navigation
  3→ *
  4→ * Design Patterns:
  5→ * - Singleton: Ensures single instance across application
  6→ * - Strategy: Configurable shortcut matching strategies
  7→ * - Observer: Event-based callback system
  8→ *
  9→ * Features:
 10→ * - Configurable shortcuts with modifier keys
 11→ * - Chrome storage integration for persistence
 12→ * - Type-safe action handling
 13→ * - Collision detection with browser shortcuts
 14→ */
 15→import { StorageKeys } from '@/core/types/common';
 16→import type {
 17→  KeyboardShortcut,
 18→  KeyboardShortcutConfig,
 19→  KeyboardShortcutStorage,
 20→  ModifierKey,
 21→  ShortcutAction,
 22→  ShortcutMatch,
 23→} from '@/core/types/keyboardShortcut';
 24→
 25→/**
 26→ * Default keyboard shortcuts configuration
 27→ * Using vim-style j/k (convenient, no modifiers needed)
 28→ */
 29→const DEFAULT_SHORTCUTS: KeyboardShortcutConfig = {
 30→  previous: {
 31→    action: 'timeline:previous',
 32→    modifiers: [],
 33→    key: 'k',
 34→  },
 35→  next: {
 36→    action: 'timeline:next',
 37→    modifiers: [],
 38→    key: 'j',
 39→  },
 40→};
 41→
 42→/**
 43→ * Callback type for shortcut actions
 44→ */
 45→export type ShortcutCallback = (action: ShortcutAction, event: KeyboardEvent) => void;
 46→
 47→/**
 48→ * KeyboardShortcutService class
 49→ * Singleton service for managing keyboard shortcuts
 50→ */
 51→export class KeyboardShortcutService {
 52→  private static instance: KeyboardShortcutService | null = null;
 53→
 54→  private config: KeyboardShortcutConfig;
 55→  private enabled: boolean = true;
 56→  private listeners: Set<ShortcutCallback> = new Set();
 57→  private keydownHandler: ((e: KeyboardEvent) => void) | null = null;
 58→  private storageChangeHandler:
 59→    | ((changes: Record<string, chrome.storage.StorageChange>, areaName: string) => void)
 60→    | null = null;
 61→
 62→  private constructor() {
 63→    this.config = DEFAULT_SHORTCUTS;
 64→  }
 65→
 66→  /**
 67→   * Get singleton instance (Factory Pattern)
 68→   */
 69→  static getInstance(): KeyboardShortcutService {
 70→    if (!KeyboardShortcutService.instance) {
 71→      KeyboardShortcutService.instance = new KeyboardShortcutService();
 72→    }
 73→    return KeyboardShortcutService.instance;
 74→  }
 75→
 76→  /**
 77→   * Initialize service: load config and attach listeners
 78→   */
 79→  async init(): Promise<void> {
 80→    await this.loadConfig();
 81→    this.attachKeyboardListener();
 82→    this.attachStorageListener();
 83→  }
 84→
 85→  /**
 86→   * Load configuration from chrome storage
 87→   */
 88→  private async loadConfig(): Promise<void> {
 89→    try {
 90→      if (typeof chrome !== 'undefined' && chrome.storage?.sync) {
 91→        const result = await chrome.storage.sync.get(StorageKeys.TIMELINE_SHORTCUTS);
 92→        const stored = result[StorageKeys.TIMELINE_SHORTCUTS] as
 93→          | KeyboardShortcutStorage
 94→          | undefined;
 95→
 96→        if (stored?.shortcuts) {
 97→          this.config = this.validateConfig(stored.shortcuts)
 98→            ? stored.shortcuts
 99→            : DEFAULT_SHORTCUTS;
100→          this.enabled = stored.enabled ?? true;
101→        }
102→      } else {
103→        // Fallback to localStorage
104→        const stored = localStorage.getItem(StorageKeys.TIMELINE_SHORTCUTS);
105→        if (stored) {
106→          const parsed = JSON.parse(stored) as KeyboardShortcutStorage;
107→          this.config = this.validateConfig(parsed.shortcuts)
108→            ? parsed.shortcuts
109→            : DEFAULT_SHORTCUTS;
110→          this.enabled = parsed.enabled ?? true;
111→        }
112→      }
113→    } catch (error) {
114→      console.warn('[KeyboardShortcut] Failed to load config, using defaults:', error);
115→      this.config = DEFAULT_SHORTCUTS;
116→      this.enabled = true;
117→    }
118→  }
119→
120→  /**
121→   * Save configuration to chrome storage
122→   */
123→  async saveConfig(config: KeyboardShortcutConfig, enabled: boolean = this.enabled): Promise<void> {
124→    if (!this.validateConfig(config)) {
125→      throw new Error('Invalid shortcut configuration');
126→    }
127→
128→    this.config = config;
129→    this.enabled = enabled;
130→
131→    const storage: KeyboardShortcutStorage = {
132→      shortcuts: config,
133→      enabled,
134→    };
135→
136→    try {
137→      if (typeof chrome !== 'undefined' && chrome.storage?.sync) {
138→        await chrome.storage.sync.set({ [StorageKeys.TIMELINE_SHORTCUTS]: storage });
139→      } else {
140→        localStorage.setItem(StorageKeys.TIMELINE_SHORTCUTS, JSON.stringify(storage));
141→      }
142→    } catch (error) {
143→      console.error('[KeyboardShortcut] Failed to save config:', error);
144→      throw error;
145→    }
146→  }
147→
148→  /**
149→   * Validate shortcut configuration
150→   */
151→  private validateConfig(config: KeyboardShortcutConfig): boolean {
152→    try {
153→      return !!(
154→        config.previous &&
155→        config.next &&
156→        this.isValidShortcut(config.previous) &&
157→        this.isValidShortcut(config.next)
158→      );
159→    } catch {
160→      return false;
161→    }
162→  }
163→
164→  /**
165→   * Validate individual shortcut
166→   */
167→  private isValidShortcut(shortcut: KeyboardShortcut): boolean {
168→    const validModifiers: ModifierKey[] = ['Alt', 'Ctrl', 'Shift', 'Meta'];
169→
170→    return (
171→      Array.isArray(shortcut.modifiers) &&
172→      shortcut.modifiers.every((m) => validModifiers.includes(m)) &&
173→      typeof shortcut.key === 'string' &&
174→      shortcut.key.length > 0
175→    );
176→  }
177→
178→  /**
179→   * Attach keyboard event listener
180→   */
181→  private attachKeyboardListener(): void {
182→    if (this.keydownHandler) return;
183→
184→    this.keydownHandler = (event: KeyboardEvent) => {
185→      if (!this.enabled) return;
186→
187→      // Ignore shortcuts when user is typing in input fields
188→      if (this.isTypingInInputField(event)) return;
189→
190→      const match = this.matchShortcut(event);
191→      if (match) {
192→        event.preventDefault();
193→        event.stopPropagation();
194→        this.notifyListeners(match.action, event);
195→      }
196→    };
197→
198→    window.addEventListener('keydown', this.keydownHandler, { capture: true });
199→  }
200→
201→  /**
202→   * Check if user is typing in an input field
203→   * Prevents shortcuts from interfering with text input
204→   */
205→  private isTypingInInputField(event: KeyboardEvent): boolean {
206→    const target = event.target as HTMLElement;
207→    if (!target) return false;
208→
209→    const tagName = target.tagName.toLowerCase();
210→    const isEditable = target.isContentEditable;
211→    const isInput = tagName === 'input' || tagName === 'textarea' || tagName === 'select';
212→
213→    return isEditable || isInput;
214→  }
215→
216→  /**
217→   * Attach storage change listener for cross-tab sync
218→   */
219→  private attachStorageListener(): void {
220→    if (typeof chrome !== 'undefined' && chrome.storage?.onChanged) {
221→      this.storageChangeHandler = (changes, areaName) => {
222→        if (areaName !== 'sync') return;
223→        if (changes[StorageKeys.TIMELINE_SHORTCUTS]) {
224→          const newValue = changes[StorageKeys.TIMELINE_SHORTCUTS].newValue as
225→            | KeyboardShortcutStorage
226→            | undefined;
227→          if (newValue?.shortcuts) {
228→            this.config = this.validateConfig(newValue.shortcuts)
229→              ? newValue.shortcuts
230→              : DEFAULT_SHORTCUTS;
231→            this.enabled = newValue.enabled ?? true;
232→          }
233→        }
234→      };
235→
236→      chrome.storage.onChanged.addListener(this.storageChangeHandler);
237→    }
238→  }
239→
240→  /**
241→   * Match keyboard event to shortcut (Strategy Pattern)
242→   */
243→  private matchShortcut(event: KeyboardEvent): ShortcutMatch | null {
244→    const shortcuts = [
245→      { action: 'timeline:previous' as const, config: this.config.previous },
246→      { action: 'timeline:next' as const, config: this.config.next },
247→    ];
248→
249→    // Check if any shortcut matches
250→    for (const { action, config } of shortcuts) {
251→      if (this.isShortcutPressed(event, config)) {
252→        return { action, event };
253→      }
254→    }
255→
256→    return null;
257→  }
258→
259→  /**
260→   * Check if specific shortcut is pressed
261→   */
262→  private isShortcutPressed(event: KeyboardEvent, shortcut: KeyboardShortcut): boolean {
263→    // Check key match
264→    if (event.key !== shortcut.key) return false;
265→
266→    // Check modifier matches
267→    const hasAlt = shortcut.modifiers.includes('Alt');
268→    const hasCtrl = shortcut.modifiers.includes('Ctrl');
269→    const hasShift = shortcut.modifiers.includes('Shift');
270→    const hasMeta = shortcut.modifiers.includes('Meta');
271→
272→    return (
273→      event.altKey === hasAlt &&
274→      event.ctrlKey === hasCtrl &&
275→      event.shiftKey === hasShift &&
276→      event.metaKey === hasMeta
277→    );
278→  }
279→
280→  /**
281→   * Notify all registered listeners (Observer Pattern)
282→   */
283→  private notifyListeners(action: ShortcutAction, event: KeyboardEvent): void {
284→    this.listeners.forEach((callback) => {
285→      try {
286→        callback(action, event);
287→      } catch (error) {
288→        console.error('[KeyboardShortcut] Error in listener callback:', error);
289→      }
290→    });
291→  }
292→
293→  /**
294→   * Register a shortcut callback
295→   */
296→  on(callback: ShortcutCallback): () => void {
297→    this.listeners.add(callback);
298→    // Return unsubscribe function
299→    return () => this.off(callback);
300→  }
301→
302→  /**
303→   * Unregister a shortcut callback
304→   */
305→  off(callback: ShortcutCallback): void {
306→    this.listeners.delete(callback);
307→  }
308→
309→  /**
310→   * Get current configuration
311→   */
312→  getConfig(): { config: KeyboardShortcutConfig; enabled: boolean } {
313→    return {
314→      config: { ...this.config },
315→      enabled: this.enabled,
316→    };
317→  }
318→
319→  /**
320→   * Reset to default shortcuts
321→   */
322→  async resetToDefaults(): Promise<void> {
323→    await this.saveConfig(DEFAULT_SHORTCUTS, true);
324→  }
325→
326→  /**
327→   * Enable/disable shortcuts
328→   */
329→  async setEnabled(enabled: boolean): Promise<void> {
330→    this.enabled = enabled;
331→    await this.saveConfig(this.config, enabled);
332→  }
333→
334→  /**
335→   * Format shortcut for display (e.g., "Alt + ↑" or "j")
336→   */
337→  formatShortcut(shortcut: KeyboardShortcut): string {
338→    // Map common keys to symbols for better display
339→    const keySymbols: Record<string, string> = {
340→      ArrowUp: '↑',
341→      ArrowDown: '↓',
342→      ArrowLeft: '←',
343→      ArrowRight: '→',
344→      ' ': 'Space',
345→      Enter: '⏎',
346→      Tab: '⇥',
347→      Backspace: '⌫',
348→      Delete: '⌦',
349→      Escape: 'Esc',
350→    };
351→
352→    const key = keySymbols[shortcut.key] || shortcut.key;
353→
354→    if (shortcut.modifiers.length === 0) {
355→      return key;
356→    }
357→
358→    const parts = [...shortcut.modifiers, key];
359→    return parts.join(' + ');
360→  }
361→
362→  /**
363→   * Cleanup service
364→   */
365→  destroy(): void {
366→    if (this.keydownHandler) {
367→      window.removeEventListener('keydown', this.keydownHandler, { capture: true });
368→      this.keydownHandler = null;
369→    }
370→
371→    if (this.storageChangeHandler && typeof chrome !== 'undefined' && chrome.storage?.onChanged) {
372→      chrome.storage.onChanged.removeListener(this.storageChangeHandler);
373→      this.storageChangeHandler = null;
374→    }
375→
376→    this.listeners.clear();
377→  }
378→}
379→
380→/**
381→ * Export singleton instance for convenience
382→ */
383→export const keyboardShortcutService = KeyboardShortcutService.getInstance();
