formatShortcut(shortcut: KeyboardShortcut): string {
  // Map common keys to symbols for better display
  const keySymbols: Record<string, string> = {
    ArrowUp: '↑',
    ArrowDown: '↓',
    ArrowLeft: '←',
    ArrowRight: '→',
    ' ': 'Space',
    Enter: '⏎',
    Tab: '⇥',
    Backspace: '⌫',
    Delete: '⌦',
    Escape: 'Esc',
  };

  const key = keySymbols[shortcut.key] || shortcut.key;

  if (shortcut.modifiers.length === 0) {
    return key;
  }

  const parts = [...shortcut.modifiers, key];
  return parts.join(' + ');
}

input.new_string:
formatShortcut(shortcut: KeyboardShortcut): string {
  // Map common keys to symbols for better display
  const keySymbols: Record<string, string> = {
    ArrowUp: '↑',
    ArrowDown: '↓',
    ArrowLeft: '←',
    ArrowRight: '→',
    ' ': 'Space',
    Enter: '⏎',
    Tab: '⇥',
    Backspace: '⌫',
    Delete: '⌦',
    Escape: 'Esc',
  };

  const key = keySymbols[shortcut.key] || shortcut.key;

  if (shortcut.modifiers.length === 0) {
    return key;
  }

  // Map modifier keys based on platform
  const mac = isMac();
  const modifierSymbols: Record<string, string> = mac
    ? { Meta: '⌘', Alt: '⌥', Ctrl: '⌃', Shift: '⇧' }
    : { Meta: 'Win', Alt: 'Alt', Ctrl: 'Ctrl', Shift: 'Shift' };

  const modifiers = shortcut.modifiers.map((m) => modifierSymbols[m] || m);
  const parts = [...modifiers, key];
  return parts.join(mac ? '' : ' + ');
}

